// DETERMINISTIC REPORT BUILDER
const raw = $input.item.json;
const record = Array.isArray(raw) ? raw[0] : raw;

const tender    = record.tender    || {};
const bidders   = record.bidders   || [];
const criteria  = record.criteria  || [];
const verdicts  = record.verdicts  || [];
const evidence  = record.evidence  || [];

// ── Deduplicate criteria by name (keep first occurrence) ──────────────
const seenCriteria = new Set();
const uniqueCriteria = criteria.filter(c => {
  if (seenCriteria.has(c.name)) return false;
  seenCriteria.add(c.name);
  return true;
});

const criterionMap = {};
uniqueCriteria.forEach(c => { criterionMap[c.id] = c; });

const verdictIndex = {}; 
verdicts.forEach(v => {
  const criterion = criteria.find(c => c.id === v.criterion_id);
  if (!criterion) return;
  const name = criterion.name;
  if (!verdictIndex[v.bidder_id]) verdictIndex[v.bidder_id] = {};
  const existing = verdictIndex[v.bidder_id][name];
  if (!existing || new Date(v.decided_at) > new Date(existing.decided_at)) {
    verdictIndex[v.bidder_id][name] = v;
  }
});

const evidenceIndex = {};
evidence.forEach(e => {
  const criterion = criteria.find(c => c.id === e.criterion_id);
  if (!criterion) return;
  const name = criterion.name;
  if (!evidenceIndex[e.bidder_id]) evidenceIndex[e.bidder_id] = {};
  const existing = evidenceIndex[e.bidder_id][name];
  if (!existing || e.confidence > existing.confidence) {
    evidenceIndex[e.bidder_id][name] = e;
  }
});

// ── Per-bidder summary ────────────────────────────────────────────────
const bidderSummaries = bidders.map(bidder => {
  const criteriaResults = uniqueCriteria.map(c => {
    const verdict  = (verdictIndex[bidder.id] || {})[c.name] || null;
    const ev       = (evidenceIndex[bidder.id] || {})[c.name] || null;

    return {
      criterion_name      : c.name,
      criterion_mandatory : c.is_mandatory,
      verdict_status      : verdict ? verdict.verdict : 'NOT_EVALUATED',
      verdict_confidence  : verdict ? verdict.confidence : null,
      verdict_reason      : verdict ? verdict.reason : null,
      evidence_text       : ev ? ev.source_text : null,
      evidence_confidence : ev ? ev.confidence : null,
      evidence_pages      : ev ? ev.source_pages : []
    };
  });

  const total           = criteriaResults.length;
  const passed          = criteriaResults.filter(r => r.verdict_status === 'PASS').length;
  const failed          = criteriaResults.filter(r => r.verdict_status === 'FAIL').length;
  const manualReview    = criteriaResults.filter(r => r.verdict_status === 'MANUAL_REVIEW').length;
  const notEvaluated    = criteriaResults.filter(r => r.verdict_status === 'NOT_EVALUATED').length;
  const mandatoryFailed = criteriaResults.filter(
    r => r.criterion_mandatory && r.verdict_status === 'FAIL'
  ).length;

  // UPDATED LOGIC:
  // 1. Mandatory Fail -> DISQUALIFIED
  // 2. Any Manual Review OR Missing Evaluation -> PENDING_REVIEW
  // 3. Any Non-Mandatory Fail -> CONDITIONAL
  // 4. Everything Passed -> ELIGIBLE
  const overallStatus = mandatoryFailed > 0
    ? 'DISQUALIFIED'
    : (manualReview > 0 || notEvaluated > 0)
      ? 'PENDING_REVIEW'
      : failed > 0
        ? 'CONDITIONAL'
        : 'ELIGIBLE';

  return {
    bidder_id          : bidder.id,
    bidder_name        : bidder.name,
    registration_number: bidder.registration_number,
    overall_status     : overallStatus,
    stats: {
      total,
      passed,
      failed,
      manual_review : manualReview,
      not_evaluated : notEvaluated,
      mandatory_failed: mandatoryFailed
    },
    criteria_results   : criteriaResults
  };
});

const reportStats = {
  total_bidders     : bidders.length,
  eligible          : bidderSummaries.filter(b => b.overall_status === 'ELIGIBLE').length,
  pending_review    : bidderSummaries.filter(b => b.overall_status === 'PENDING_REVIEW').length,
  disqualified      : bidderSummaries.filter(b => b.overall_status === 'DISQUALIFIED').length,
  conditional       : bidderSummaries.filter(b => b.overall_status === 'CONDITIONAL').length,
  total_criteria    : uniqueCriteria.length,
  total_verdicts    : verdicts.length,
  total_evidence    : evidence.length
};

const narrativePrompt = `
Tender: ${tender.name || 'Unnamed'}
Status: ${tender.status}
Total bidders: ${reportStats.total_bidders}
Eligible: ${reportStats.eligible}
Pending manual review: ${reportStats.pending_review}
Disqualified: ${reportStats.disqualified}
Criteria evaluated: ${reportStats.total_criteria}
Bidder outcomes: ${bidderSummaries.map(b => b.bidder_name + ' → ' + b.overall_status).join(', ')}
`.trim();

return {
  json: {
    report_generated_at : new Date().toISOString(),
    tender,
    report_stats        : reportStats,
    unique_criteria     : uniqueCriteria,
    bidder_summaries    : bidderSummaries,
    llm_narrative_prompt: narrativePrompt
  }
};

