// Get the raw text from the Mistral response
const llmResponse = $input.first().json;
const reportData = $('Build Report Data (Deterministic)').first().json;

// Extract the content from the specific path Mistral uses
let narrativeText = llmResponse.choices?.[0]?.message?.content || "";

// Clean up any stray quotes or whitespace
narrativeText = narrativeText.trim();

// Since Mistral followed instructions and gave prose, 
// we use the whole thing as the summary.
let narrative = {
  summary: narrativeText,
  recommendation: 'Financial bids of eligible bidders may be opened as per schedule. Rejection letters to be issued to ineligible bidders with specific criterion references.'
};

// Merge into the report data
return [{
  json: {
    ...reportData,
    narrative
  }
}];

const d = $input.first().json;

const {
  tender,
  bidder_summaries: bidderCards,
  unique_criteria: criteriaRaw,
  narrative,
  report_generated_at: generated_at
} = d;

// ── Sort criteria ──
const criteria = [...(criteriaRaw || [])].sort(
  (a, b) => (a.order_index ?? 0) - (b.order_index ?? 0)
);

// Summary Stats
const eligible = bidderCards.filter(b => b.overall_status === 'ELIGIBLE');
const ineligible = bidderCards.filter(b => b.overall_status === 'DISQUALIFIED');

// Colors & Branding
const NAVY = '#1B3A6B';
const GREEN = '#1A5C35';
const GREEN_LIGHT = '#D4F0DC';
const RED = '#7A1F1F';
const RED_LIGHT = '#FAE0E0';
const AMBER = '#7A4E00';
const AMBER_LIGHT = '#FFF3CD';
const GRAY = '#595959';
const BORDER = '#CCCCCC';

/**
 * Enhanced Badge Helper with Icons
 * @param {string} verdict - The status string
 * @param {boolean} isMatrix - If true, shows ONLY the icon to save space
 */
function verdictBadge(verdict, isMatrix = false) {
  const map = {
    ELIGIBLE:       { bg: GREEN_LIGHT, color: GREEN, label: 'PASS', icon: '✔' },
    PASS:           { bg: GREEN_LIGHT, color: GREEN, label: 'PASS', icon: '✔' },
    DISQUALIFIED:   { bg: RED_LIGHT,   color: RED,   label: 'FAIL', icon: '✘' },
    FAIL:           { bg: RED_LIGHT,   color: RED,   label: 'FAIL', icon: '✘' },
    PENDING_REVIEW: { bg: AMBER_LIGHT, color: AMBER, label: 'REVIEW', icon: '⚠' },
    MANUAL_REVIEW:  { bg: AMBER_LIGHT, color: AMBER, label: 'REVIEW', icon: '⚠' }
  };

  const s = map[verdict] || { bg: '#F2F4F7', color: GRAY, label: verdict || '—', icon: '?' };

  // Matrix style: Square, icon-focused
  if (isMatrix) {
    return `<span style="background:${s.bg};color:${s.color};font-weight:bold;width:22px;height:22px;line-height:22px;border-radius:50%;font-size:12px;display:inline-block;text-align:center;border:1px solid rgba(0,0,0,0.05)">${s.icon}</span>`;
  }

  // Detailed style: Rounded rectangle with Label
  return `<span style="background:${s.bg};color:${s.color};font-weight:bold;padding:4px 8px;border-radius:3px;font-size:10px;white-space:nowrap;display:inline-block;border:1px solid rgba(0,0,0,0.1)">${s.icon} ${s.label}</span>`;
}

// Table Style Helpers
function th(text, width = 'auto') {
  return `<th style="background:${NAVY};color:#ffffff;padding:8px 4px;text-align:center;font-size:10px;border:1px solid #ffffff;width:${width};word-wrap:break-word;">${text}</th>`;
}

// ── 1. Master Matrix Row Generation ──
let matrixRows = '';
for (const bidder of bidderCards) {
  let criteriaCells = '';

  criteria.forEach(c => {
    const res = (bidder.criteria_results || []).find(r => 
        (r.criterion_id && r.criterion_id === c.id) || 
        (r.criterion_name === c.criterion_name) ||
        (r.name === c.name)
    );
    // Use the Matrix-specific badge (Icon circle)
    criteriaCells += `<td style="padding:6px;border:1px solid ${BORDER};text-align:center;">${verdictBadge(res?.verdict_status, true)}</td>`;
  });

  matrixRows += `<tr>
    <td style="padding:8px;border:1px solid ${BORDER};font-size:11px;font-weight:bold;background:#Fcfcfc;">${bidder.bidder_name}</td>
    ${criteriaCells}
    <td style="padding:6px;border:1px solid ${BORDER};text-align:center;background:#Fcfcfc;">${verdictBadge(bidder.overall_status)}</td>
  </tr>`;
}

let matrixHeaders = th('Bidder Name', '20%');
criteria.forEach((_, i) => { matrixHeaders += th(`C${i + 1}`, 'auto'); });
matrixHeaders += th('Overall Status', '15%');

// ── 2. Legend Generation ──
let legendItems = '';
criteria.forEach((cr, i) => {
  legendItems += `<div style="font-size:10px; margin-bottom:2px;"><strong>C${i+1}:</strong> ${cr.name || cr.criterion_name}</div>`;
});

// ── 3. Bidder Detailed Sections ──
let bidderSections = '';
for (const bidder of bidderCards) {
  let criterionRows = '';
  const sortedResults = [...(bidder.criteria_results || [])].sort((a, b) => (a.order_index ?? 0) - (b.order_index ?? 0));

  sortedResults.forEach((cr, i) => {
    criterionRows += `<tr>
      <td style="padding:8px; border:1px solid ${BORDER}; text-align:center; font-size:10px;">C${i + 1}</td>
      <td style="padding:8px; border:1px solid ${BORDER}; font-weight:bold; font-size:11px; width:180px;">${cr.criterion_name || cr.name || '—'}</td>
      <td style="padding:8px; border:1px solid ${BORDER}; font-size:10px; color:#333; line-height:1.4;">${cr.verdict_reason || '—'}</td>
      <td style="padding:8px; border:1px solid ${BORDER}; font-size:10px; color:${GRAY};">
        ${cr.evidence_text ? `<em>&ldquo;${cr.evidence_text}&rdquo;</em><br><small style="display:block;margin-top:4px;">Page: ${cr.evidence_pages?.join(',') || 'N/A'}</small>` : '—'}
      </td>
      <td style="padding:8px; border:1px solid ${BORDER}; text-align:center;">${verdictBadge(cr.verdict_status)}</td>
    </tr>`;
  });

  const statusColor = bidder.overall_status === 'ELIGIBLE' ? GREEN : bidder.overall_status === 'DISQUALIFIED' ? RED : AMBER;
  const statusBg = bidder.overall_status === 'ELIGIBLE' ? GREEN_LIGHT : bidder.overall_status === 'DISQUALIFIED' ? RED_LIGHT : AMBER_LIGHT;

  bidderSections += `
    <div style="margin-top:30px; border:1px solid ${BORDER}; border-radius:4px; page-break-inside:avoid; overflow:hidden;">
      <div style="background:${statusBg}; padding:12px; border-bottom:2px solid ${statusColor}; display:flex; justify-content:space-between; align-items:center;">
        <strong style="color:${statusColor}; font-size:14px;">${bidder.bidder_name}</strong>
        <span style="font-size:10px; font-weight:bold; color:${statusColor}">${bidder.overall_status}</span>
      </div>
      <table width="100%" style="border-collapse:collapse; table-layout:fixed;">
        <thead>
          <tr>
            ${th('Ref','40px')}
            ${th('Criterion','20%')}
            ${th('Evaluation Note','40%')}
            ${th('Source Evidence','25%')}
            ${th('Verdict','12%')}
          </tr>
        </thead>
        <tbody>${criterionRows}</tbody>
      </table>
    </div>`;
}

// ── 4. Final HTML ──
const html = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    @page { size: A4; margin: 1.2cm; }
    body { font-family: "Segoe UI", Roboto, Helvetica, Arial, sans-serif; line-height: 1.5; color: #222; margin: 0; }
    .header-box { text-align: center; padding: 25px; background: ${NAVY}; color: white; border-bottom: 4px solid #DAA520; }
    .section-title { color: ${NAVY}; border-bottom: 2px solid ${NAVY}; padding-bottom: 5px; margin-top: 30px; font-size: 16px; text-transform: uppercase; letter-spacing: 0.5px; }
    .legend-box { background: #f9f9f9; padding: 12px; border: 1px solid ${BORDER}; margin-top: 10px; display: grid; grid-template-columns: 1fr 1fr; gap: 8px; border-radius: 4px; }
  </style>
</head>
<body>
  <div class="header-box">
    <div style="font-size:20px; font-weight:bold; letter-spacing:2px; margin-bottom:8px; opacity:0.9;">UNNATI - SMART TENDER AI</div>
    <div style="font-size:13px; opacity:0.9;">TECHNICAL BID EVALUATION: <span style="color:#FFD700">${tender?.name || 'Tender Evaluation'}</span></div>
    <div style="font-size:10px; margin-top:10px; opacity:0.7;">REF: ${tender?.reference_number || 'N/A'}</div>
  </div>

  <h3 class="section-title">1. Executive Summary</h3>
  <div style="font-size:12px; background:#fcfcfc; padding:15px; border-radius:4px; border:1px solid #eee;">
    <p>${narrative?.summary || 'Evaluation summary is currently being compiled based on bidder submissions.'}</p>
    <p><strong>Committee Recommendation:</strong> ${narrative?.recommendation || 'Pending final review of manual flags.'}</p>
  </div>

  <h3 class="section-title">2. Master Eligibility Matrix</h3>
  <table width="100%" style="border-collapse:collapse; table-layout:fixed; margin-top:10px;">
    <thead><tr>${matrixHeaders}</tr></thead>
    <tbody>${matrixRows}</tbody>
  </table>

  <div style="display: flex; justify-content: space-between; align-items: flex-start; margin-top: 15px;">
    <div style="width: 65%;">
        <div style="font-size:10px; font-weight:bold; color:${NAVY}">CRITERION LEGEND:</div>
        <div class="legend-box">${legendItems}</div>
    </div>
    <div style="width: 30%; background: #fff; border: 1px solid ${BORDER}; padding: 10px; border-radius: 4px;">
        <div style="font-size:10px; font-weight:bold; color:${NAVY}; margin-bottom: 5px;">KEY:</div>
        <div style="font-size: 10px;"><span style="color:${GREEN}">✔</span> Pass</div>
        <div style="font-size: 10px;"><span style="color:${RED}">✘</span> Fail</div>
        <div style="font-size: 10px;"><span style="color:${AMBER}">⚠</span> Manual Review</div>
    </div>
  </div>

  <h3 class="section-title">3. Detailed Bidder Observations</h3>
  ${bidderSections}

  <div style="margin-top:50px; border-top:1px solid #eee; padding-top:15px; font-size:9px; color:${GRAY}; text-align:center;">
    This technical evaluation report was generated automatically by <strong>Unnati Smart Tender AI</strong>.<br>
    Final authority for bidder qualification remains with the designated Tender Opening Committee.<br>
    Timestamp: ${new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' })}
  </div>
</body>
</html>`;

return [{
  json: {
    tender_id: tender?.id || "N/A",
    html_content: html,
    report_metadata: {
      total_bidders: bidderCards.length,
      eligible_count: eligible.length,
      disqualified_count: ineligible.length
    }
  }
}];
